// src/hooks/useSensor.js
import { useState, useEffect } from 'react';
import sensorService from '../services/sensorService';

export const useSensor = () => {
    const [status, setStatus] = useState({ connected: false, port: 'Unknown' });
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        checkStatus();
        const interval = setInterval(checkStatus, 30000);
        return () => clearInterval(interval);
    }, []);

    const checkStatus = async () => {
        try {
            const data = await sensorService.getStatus();
            setStatus(data);
        } catch (error) {
            console.error('Sensor check failed:', error);
        } finally {
            setLoading(false);
        }
    };

    return { status, loading, refresh: checkStatus };
};
